    function toString(uint256 value) internal pure returns (string memory) {
        unchecked {
            uint256 length = Math.log10(value) + 1;
            string memory buffer = new string(length);
            uint256 ptr;
            /// @solidity memory-safe-assembly
            assembly {
                ptr := add(buffer, add(32, length))
            }
            while (true) {
                ptr--;
                /// @solidity memory-safe-assembly
                assembly {
                    mstore8(ptr, byte(mod(value, 10), _SYMBOLS))
                }
                value /= 10;
                if (value == 0) break;
            }
            return buffer;
        }
    }

    /**
     * @dev Converts a `int256` to its ASCII `string` decimal representation.
     */
    function toString(int256 value) internal pure returns (string memory) {
        return string(abi.encodePacked(value < 0 ? "-" : "", toString(SignedMath.abs(value))));
    }

    /**
     * @dev Converts a `uint256` to its ASCII `string` hexadecimal representation.
     */
    function toHexString(uint256 value) internal pure returns (string memory) {
        unchecked {
            return toHexString(value, Math.log256(value) + 1);
        }
    }

    /**
     * @dev Converts a `uint256` to its ASCII `string` hexadecimal representation with fixed length.
     */
    function toHexString(uint256 value, uint256 length) internal pure returns (string memory) {
        bytes memory buffer = new bytes(2 * length + 2);
        buffer[0] = "0";
        buffer[1] = "x";
        for (uint256 i = 2 * length + 1; i > 1; --i) {
            buffer[i] = _SYMBOLS[value & 0xf];
            value >>= 4;
        }
        require(value == 0, "Strings: hex length insufficient");
        return string(buffer);
    }

    /**
     * @dev Converts an `address` with fixed length of 20 bytes to its not checksummed ASCII `string` hexadecimal representation.
     */
    function toHexString(address addr) internal pure returns (string memory) {
        return toHexString(uint256(uint160(addr)), _ADDRESS_LENGTH);
    }

    /**
     * @dev Returns true if the two strings are equal.
     */
    function equal(string memory a, string memory b) internal pure returns (bool) {
        return keccak256(bytes(a)) == keccak256(bytes(b));
    }
}

contracts/AssetBackedExchange.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AssetBackedExchange
 * @notice Decentralized exchange for trading asset-backed security tokens
 *         against ETH (native), WETH, WBTC, and any ERC-20 token.
 *
 *         Supports:
 *         - Limit orders (token/token)
 *         - ETH-based orders (buy or sell with native ETH)
 *         - Partial fills
 *         - Order cancellation
 *
 * @dev Uses a pull-based pattern for ETH refunds to prevent reentrancy.
 *      All ERC-20 interactions use the standard interface.
 */

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract AssetBackedExchange {

    // ---------------------------------------------------------------
    //  Constants
    // ---------------------------------------------------------------

    /// @notice Sentinel address representing native ETH in order pairs.
    address public constant ETH_ADDRESS = 0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE;

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    struct Order {
        uint256 id;
        address maker;
        address tokenSell;     // what the maker is selling (ETH_ADDRESS for native ETH)
        address tokenBuy;      // what the maker wants to buy (ETH_ADDRESS for native ETH)
        uint256 amountSell;    // total sell amount
        uint256 amountBuy;     // total buy amount (price = amountBuy/amountSell)
        uint256 filledSell;    // amount already filled on sell side
        uint256 filledBuy;     // amount already filled on buy side
        bool    cancelled;
    }

    uint256 public nextOrderId;
    mapping(uint256 => Order) private _orders;

    /// @notice maker address => array of their order IDs
    mapping(address => uint256[]) private _userOrderIds;

    /// @notice Refundable ETH balances (for cancelled ETH-sell orders)
    mapping(address => uint256) public ethBalances;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event OrderCreated(
        uint256 indexed orderId,
        address indexed maker,
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    );

    event OrderFilled(
        uint256 indexed orderId,
        address indexed taker,
        uint256 fillAmountSell,
        uint256 fillAmountBuy
    );

    event OrderCancelled(uint256 indexed orderId, address indexed maker);

    event EthWithdrawn(address indexed to, uint256 amount);

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error ZeroAmount();
    error ZeroAddress();
    error SameToken();
    error OrderNotActive();
    error NotMaker();
    error InsufficientFill();
    error TransferFailed();
    error InsufficientEth();
    error NothingToWithdraw();

    // ---------------------------------------------------------------
    //  Create order
    // ---------------------------------------------------------------

    /**
     * @notice Create a limit order to sell an ERC-20 token.
     *         For selling native ETH, use createOrderSellETH instead.
     *
     * @param tokenSell  The ERC-20 token being sold
     * @param tokenBuy   The token wanted in return (ETH_ADDRESS for native ETH)
     * @param amountSell Amount of tokenSell to offer
     * @param amountBuy  Amount of tokenBuy desired (sets the price)
     */
    function createOrder(
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) external returns (uint256 orderId) {
        if (amountSell == 0 || amountBuy == 0) revert ZeroAmount();
        if (tokenSell == address(0) || tokenBuy == address(0)) revert ZeroAddress();
        if (tokenSell == tokenBuy) revert SameToken();
        if (tokenSell == ETH_ADDRESS) revert ZeroAddress(); // use createOrderSellETH

        // Transfer sell tokens to this contract
        bool ok = IERC20(tokenSell).transferFrom(msg.sender, address(this), amountSell);
        if (!ok) revert TransferFailed();

        orderId = _createOrder(msg.sender, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    /**
     * @notice Create a limit order selling native ETH for an ERC-20 token.
     *
     * @param tokenBuy   The ERC-20 token wanted in return
     * @param amountBuy  Amount of tokenBuy desired
     */
    function createOrderSellETH(
        address tokenBuy,
        uint256 amountBuy
    ) external payable returns (uint256 orderId) {
        if (msg.value == 0 || amountBuy == 0) revert ZeroAmount();
        if (tokenBuy == address(0) || tokenBuy == ETH_ADDRESS) revert ZeroAddress();

        orderId = _createOrder(msg.sender, ETH_ADDRESS, tokenBuy, msg.value, amountBuy);
    }

    function _createOrder(
        address maker,
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) private returns (uint256 orderId) {
        orderId = nextOrderId++;

        _orders[orderId] = Order({
            id: orderId,
            maker: maker,
            tokenSell: tokenSell,
            tokenBuy: tokenBuy,
            amountSell: amountSell,
            amountBuy: amountBuy,
            filledSell: 0,
            filledBuy: 0,
            cancelled: false
        });

        _userOrderIds[maker].push(orderId);

        emit OrderCreated(orderId, maker, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    // ---------------------------------------------------------------
    //  Fill order
    // ---------------------------------------------------------------

    /**
     * @notice Fill an existing order by providing the buy-side token.
     *         For orders where tokenBuy is ETH, use fillOrderWithETH.
     *
     * @param orderId       The order to fill
     * @param fillAmountBuy Amount of the buy token to provide
     */
    function fillOrder(uint256 orderId, uint256 fillAmountBuy) external {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (fillAmountBuy == 0) revert ZeroAmount();
        if (order.tokenBuy == ETH_ADDRESS) revert ZeroAddress(); // use fillOrderWithETH

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        if (fillAmountBuy > remainingBuy) fillAmountBuy = remainingBuy;

        // Calculate proportional sell amount
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert InsufficientFill();

        order.filledBuy += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Taker sends buy tokens to maker
        bool ok = IERC20(order.tokenBuy).transferFrom(msg.sender, order.maker, fillAmountBuy);
        if (!ok) revert TransferFailed();

        // Taker receives sell tokens from escrow
        if (order.tokenSell == ETH_ADDRESS) {
            (bool sent,) = payable(msg.sender).call{value: fillAmountSell}("");
            if (!sent) revert TransferFailed();
        } else {
            ok = IERC20(order.tokenSell).transfer(msg.sender, fillAmountSell);
            if (!ok) revert TransferFailed();
        }

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    /**
     * @notice Fill an order where the buy-side is native ETH.
     *
     * @param orderId The order to fill
     */
    function fillOrderWithETH(uint256 orderId) external payable {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (msg.value == 0) revert ZeroAmount();
        if (order.tokenBuy != ETH_ADDRESS) revert ZeroAddress(); // use fillOrder

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        uint256 fillAmountBuy = msg.value > remainingBuy ? remainingBuy : msg.value;

        // Calculate proportional sell amount
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert InsufficientFill();

        order.filledBuy += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Send ETH to maker
        (bool sentToMaker,) = payable(order.maker).call{value: fillAmountBuy}("");
        if (!sentToMaker) revert TransferFailed();

        // Send sell tokens to taker
        bool ok = IERC20(order.tokenSell).transfer(msg.sender, fillAmountSell);
        if (!ok) revert TransferFailed();

        // Refund excess ETH to taker
        if (msg.value > fillAmountBuy) {
            (bool refund,) = payable(msg.sender).call{value: msg.value - fillAmountBuy}("");
            if (!refund) revert TransferFailed();
        }

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    // ---------------------------------------------------------------
    //  Cancel order
    // ---------------------------------------------------------------

    /**
     * @notice Cancel an open order and return unfilled tokens to the maker.
     */
    function cancelOrder(uint256 orderId) external {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (msg.sender != order.maker) revert NotMaker();

        order.cancelled = true;

        // Return unfilled sell tokens
        uint256 remaining = order.amountSell - order.filledSell;
        if (remaining > 0) {
            if (order.tokenSell == ETH_ADDRESS) {
                // Credit ETH balance for pull-based withdrawal
                ethBalances[order.maker] += remaining;
            } else {
                bool ok = IERC20(order.tokenSell).transfer(order.maker, remaining);
                if (!ok) revert TransferFailed();
            }
        }

        emit OrderCancelled(orderId, msg.sender);
    }

    /**
     * @notice Withdraw credited ETH (from cancelled ETH-sell orders).
     */
    function withdrawEth() external {
        uint256 balance = ethBalances[msg.sender];
        if (balance == 0) revert NothingToWithdraw();
        ethBalances[msg.sender] = 0;

        (bool sent,) = payable(msg.sender).call{value: balance}("");
        if (!sent) revert TransferFailed();

        emit EthWithdrawn(msg.sender, balance);
    }

    // ---------------------------------------------------------------
    //  View functions
    // ---------------------------------------------------------------

    function getOrder(uint256 orderId) external view returns (Order memory) {
        return _orders[orderId];
    }

    function getUserOrders(address user) external view returns (uint256[] memory) {
        return _userOrderIds[user];
    }

    function getOrderCount() external view returns (uint256) {
        return nextOrderId;
    }

    /**
     * @notice Get all active (non-cancelled, not fully filled) orders
     *         for a specific trading pair.
     */
    function getActiveOrders(
        address tokenSell,
        address tokenBuy
    ) external view returns (Order[] memory) {
        // Count matching orders first
        uint256 count = 0;
        for (uint256 i = 0; i < nextOrderId; i++) {
            Order storage o = _orders[i];
            if (o.tokenSell == tokenSell &&
                o.tokenBuy == tokenBuy &&
                !o.cancelled &&
                o.filledSell < o.amountSell) {
                count++;
            }
        }

        // Build result array
        Order[] memory result = new Order[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < nextOrderId; i++) {
            Order storage o = _orders[i];
            if (o.tokenSell == tokenSell &&
                o.tokenBuy == tokenBuy &&
                !o.cancelled &&
                o.filledSell < o.amountSell) {
                result[idx++] = o;
            }
        }
        return result;
    }

    // ---------------------------------------------------------------
    //  Internal
    // ---------------------------------------------------------------

    function _validateOrderActive(Order storage order) private view {
        if (order.cancelled) revert OrderNotActive();
        if (order.filledSell >= order.amountSell) revert OrderNotActive();
    }

    // ---------------------------------------------------------------
    //  Receive ETH
    // ---------------------------------------------------------------

    receive() external payable {}
}

contracts/AssetExchange.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AssetExchange
 * @notice A fully on-chain limit-order book for ERC-20 token pairs.
 *
 *         Makers create orders specifying the tokens and amounts they wish to
 *         swap.  Takers fill orders by providing the requested buy-side tokens
 *         and receiving the sell-side tokens held in escrow.
 *
 *         Orders can be partially filled.  Makers may cancel any unfilled
 *         portion of their orders at any time.
 *
 * @dev    Implements a manual reentrancy guard (no external imports).
 *         All token transfers use a safe low-level call wrapper that reverts
 *         on failure, defending against non-compliant ERC-20 implementations.
 */
contract AssetExchange {

    // ---------------------------------------------------------------
    //  Reentrancy guard
    // ---------------------------------------------------------------

    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED     = 2;
    uint256 private _status = _NOT_ENTERED;

    modifier nonReentrant() {
        if (_status == _ENTERED) revert ReentrancyDetected();
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    // ---------------------------------------------------------------
    //  Data structures
    // ---------------------------------------------------------------

    struct Order {
        uint256 id;
        address maker;
        address tokenSell;
        address tokenBuy;
        uint256 amountSell;      // total sell-side amount committed
        uint256 amountBuy;       // total buy-side amount requested
        uint256 filledSell;      // cumulative sell-side tokens transferred out
        uint256 filledBuy;       // cumulative buy-side tokens received by maker
        bool    cancelled;
    }

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    /// @notice Auto-incrementing order counter. First valid id is 1.
    uint256 public nextOrderId = 1;

    /// @notice orderId => Order
    mapping(uint256 => Order) public orders;

    /// @notice Ordered pair key => array of order ids that belong to this pair.
    ///         The key is `keccak256(abi.encodePacked(tokenSell, tokenBuy))`.
    mapping(bytes32 => uint256[]) private _pairOrderIds;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event OrderCreated(
        uint256 indexed orderId,
        address indexed maker,
        address         tokenSell,
        address         tokenBuy,
        uint256         amountSell,
        uint256         amountBuy
    );

    event OrderFilled(
        uint256 indexed orderId,
        address indexed taker,
        uint256         fillAmountSell,
        uint256         fillAmountBuy
    );

    event OrderCancelled(
        uint256 indexed orderId,
        address indexed maker
    );

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error ReentrancyDetected();
    error ZeroAddress();
    error ZeroAmount();
    error SameToken();
    error OrderDoesNotExist();
    error OrderAlreadyCancelled();
    error OrderFullyFilled();
    error NotOrderMaker();
    error FillAmountTooLarge();
    error TransferFailed();

    // ---------------------------------------------------------------
    //  External: create order
    // ---------------------------------------------------------------

    /**
     * @notice Create a new limit order.
     *
     *         The maker commits `amountSell` of `tokenSell` (transferred into
     *         escrow immediately) and requests `amountBuy` of `tokenBuy` in
     *         return.
     *
     * @param tokenSell  Address of the ERC-20 being sold.
     * @param tokenBuy   Address of the ERC-20 being bought.
     * @param amountSell Total sell-side amount to escrow.
     * @param amountBuy  Total buy-side amount desired.
     *
     * @return orderId   The id of the newly created order.
     */
    function createOrder(
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) external nonReentrant returns (uint256 orderId) {
        if (tokenSell == address(0) || tokenBuy == address(0)) revert ZeroAddress();
        if (tokenSell == tokenBuy) revert SameToken();
        if (amountSell == 0 || amountBuy == 0) revert ZeroAmount();

        orderId = nextOrderId++;

        orders[orderId] = Order({
            id:         orderId,
            maker:      msg.sender,
            tokenSell:  tokenSell,
            tokenBuy:   tokenBuy,
            amountSell: amountSell,
            amountBuy:  amountBuy,
            filledSell: 0,
            filledBuy:  0,
            cancelled:  false
        });

        bytes32 pairKey = _pairKey(tokenSell, tokenBuy);
        _pairOrderIds[pairKey].push(orderId);

        // Transfer sell tokens from maker into this contract (escrow).
        _safeTransferFrom(tokenSell, msg.sender, address(this), amountSell);

        emit OrderCreated(orderId, msg.sender, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    // ---------------------------------------------------------------
    //  External: fill order
    // ---------------------------------------------------------------

    /**
     * @notice Fill (partially or fully) an existing order.
     *
     *         The taker sends `fillAmountBuy` of the order's `tokenBuy` to the
     *         maker.  In return the taker receives the proportional amount of
     *         the order's `tokenSell` from escrow.
     *
     *         The proportional sell amount is:
     *             fillAmountSell = fillAmountBuy * amountSell / amountBuy
     *
     * @param orderId      The order to fill.
     * @param fillAmountBuy Amount of tokenBuy the taker is providing.
     */
    function fillOrder(
        uint256 orderId,
        uint256 fillAmountBuy
    ) external nonReentrant {
        Order storage order = orders[orderId];
        if (order.maker == address(0)) revert OrderDoesNotExist();
        if (order.cancelled) revert OrderAlreadyCancelled();
        if (fillAmountBuy == 0) revert ZeroAmount();

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        if (remainingBuy == 0) revert OrderFullyFilled();
        if (fillAmountBuy > remainingBuy) revert FillAmountTooLarge();

        // Calculate the proportional sell amount.
        // Using full-precision multiplication then division to minimize rounding.
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert ZeroAmount();

        // Update state before external calls (checks-effects-interactions).
        order.filledBuy  += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Taker sends buy-side tokens to the maker.
        _safeTransferFrom(order.tokenBuy, msg.sender, order.maker, fillAmountBuy);

        // Contract sends escrowed sell-side tokens to the taker.
        _safeTransfer(order.tokenSell, msg.sender, fillAmountSell);

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    // ---------------------------------------------------------------
    //  External: cancel order
    // ---------------------------------------------------------------

    /**
     * @notice Cancel an open order. Only the original maker may cancel.
     *         Any un-filled sell-side tokens are returned from escrow to
     *         the maker.
     *
     * @param orderId The order to cancel.
     */
    function cancelOrder(uint256 orderId) external nonReentrant {
        Order storage order = orders[orderId];
        if (order.maker == address(0)) revert OrderDoesNotExist();
        if (order.cancelled) revert OrderAlreadyCancelled();
        if (order.maker != msg.sender) revert NotOrderMaker();

        order.cancelled = true;

        // Refund un-filled sell tokens.
        uint256 remaining = order.amountSell - order.filledSell;
        if (remaining > 0) {
            _safeTransfer(order.tokenSell, msg.sender, remaining);
        }

        emit OrderCancelled(orderId, msg.sender);
    }

    // ---------------------------------------------------------------
    //  View: order queries
    // ---------------------------------------------------------------

    /**
     * @notice Return all *active* (not cancelled, not fully filled) order ids
     *         for the directed pair (tokenSell => tokenBuy).
     *
     * @param tokenSell Sell-side token address.
     * @param tokenBuy  Buy-side token address.
     *
     * @return activeOrders Array of Order structs that are still active.
     */
    function getOrders(
        address tokenSell,
        address tokenBuy
    ) external view returns (Order[] memory activeOrders) {
        bytes32 pairKey = _pairKey(tokenSell, tokenBuy);
        uint256[] storage ids = _pairOrderIds[pairKey];
        uint256 len = ids.length;

        // First pass: count active orders so we can size the return array.
        uint256 count;
        for (uint256 i; i < len; ++i) {
            Order storage o = orders[ids[i]];
            if (!o.cancelled && o.filledBuy < o.amountBuy) {
                ++count;
            }
        }

        // Second pass: populate the return array.
        activeOrders = new Order[](count);
        uint256 idx;
        for (uint256 i; i < len; ++i) {
            Order storage o = orders[ids[i]];
            if (!o.cancelled && o.filledBuy < o.amountBuy) {
                activeOrders[idx++] = o;
            }
        }
    }

    /**
     * @notice Retrieve a single order by its id.
     * @param orderId The order id.
     */
    function getOrder(uint256 orderId) external view returns (Order memory) {
        if (orders[orderId].maker == address(0)) revert OrderDoesNotExist();
        return orders[orderId];
    }

    // ---------------------------------------------------------------
    //  Internal helpers
    // ---------------------------------------------------------------

    /**
     * @dev Deterministic key for a directed token pair.
     *      (tokenA, tokenB) and (tokenB, tokenA) produce *different* keys.
     *      This is intentional: sell orders A->B are conceptually distinct
     *      from sell orders B->A.
     */
    function _pairKey(address tokenA, address tokenB) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(tokenA, tokenB));
    }

    /**
     * @dev Safely call `IERC20.transferFrom(from, to, amount)`.
     *      Handles tokens that return bool as well as tokens that return
     *      nothing (USDT-style).
     */
    function _safeTransferFrom(
        address token,
        address from,
        address to,
        uint256 amount
    ) internal {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(
                // bytes4(keccak256("transferFrom(address,address,uint256)"))
                0x23b872dd,
                from,
                to,
                amount
            )
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }

    /**
     * @dev Safely call `IERC20.transfer(to, amount)`.
     */
    function _safeTransfer(
        address token,
        address to,
        uint256 amount
    ) internal {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(
                // bytes4(keccak256("transfer(address,uint256)"))
                0xa9059cbb,
                to,
                amount
            )
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }
}

contracts/security-token/interfaces/IDiv.content:
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.4;



interface IDividends  {

  /************************
   * Functions
   ************************/

  /// @dev Get unused ERC-20 tokens on snapshot
  /// @param token ERC-20 token address
  /// @param snapshotId Snapshot ID
  /// @return amount of ERC-20 tokens
  function tokensAt(address token, uint256 snapshotId) external view returns (uint256);

  /// @dev Withdrawal remains of unused ERC-20 tokens at snapshot
  /// @param token ERC-20 token address
  /// @param snapshotId Snapshot ID
  function withdrawalRemains(address token, uint256 snapshotId) external;

  /**
   * @dev Fund any ERC-20 tokens into current contract
   * Tokens can be claimed by holders of RestrictedSwap Token uses claimDividends method
   * @param token ERC-20 token address
   * @param amount amount of tokens to fund
   * @param snapshotId snapshot ID of RestrictedSwap Token
   */
  function fundDividend(address token, uint256 amount, uint256 snapshotId) external;

  /**
   * @dev Get balance of ERC-20 tokens funded at snapshot
   * @param token ERC-20 token address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of ERC-20 tokens
   */
  function fundsAt(address token, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Amount of ERC-20 tokens distributed to the holder of RestrictedSwap Token at snapshot
   * @param token ERC-20 token address
   * @param receiver RestrictedSwap Token's holder address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of total ERC-20 tokens distributed to the receiver
   */
  function totalAwardedBalanceAt(address token, address receiver, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Amount of ERC-20 tokens claimed by the holder of RestrictedSwap Token at snapshot
   * @param token ERC-20 token address
   * @param receiver RestrictedSwap Token's holder address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of claimed ERC-20 tokens
   */
  function claimedBalanceAt(address token, address receiver, uint256 snapshotId) external view returns (uint256);

  /**
